import { useParams } from "react-router-dom";
import { useState, useEffect } from "react";
import axios from "axios";

const EditUser = () => {
    const { userID } = useParams(); // Get user ID from URL
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        axios.get(`http://localhost:5000/api/user/${userID}`)
            .then(response => {
                setUser(response.data);
                setLoading(false);
            })
            .catch(error => {
                console.error("Error fetching user data:", error);
                setError("Failed to load user data.");
                setLoading(false);
            });
    }, [userID]);

    if (loading) return <p>Loading user data...</p>;
    if (error) return <p>{error}</p>;

    return (
        <div className="table-container">
            <h2>Endre bruker {user.p_key}</h2>
            <p><strong>Navn:</strong> {user.s_name}</p>
            <p><strong>Epost:</strong> {user.s_email}</p>
            <p><strong>Brukertype:</strong> {user.i_user}</p>
            <p><strong>Reg.nummer:</strong> {user.s_regno}</p>
            <p><strong>Aktive:</strong> {user.b_active}</p>
        </div>
    );
};

export default EditUser;
